export const SkillFrontmatterSchema = z.object({
  name: z.string().regex(/^[a-z0-9-]+$/),
  description: z.string().min(1),
});

export type SkillManifest = {
  name: string;
  description: string;
  hasCommand: boolean;      // command/<name>.md exists
  path: string;             // .lightfast/skills/<name>/
};

export type DotLightfastConfig = {
  spec: string | null;        // SPEC.md content
  skills: SkillManifest[];    // just manifests, not full bodies
  memoryIndex: string | null; // memory/MEMORY.md content, null for v1
};
```

**Parser signature** (new, does NOT use `readFile`):
```ts
type Fetcher = (path: string) => Promise<
  | { type: "file"; content: string }
  | { type: "dir"; entries: { name: string; type: "file" | "dir" }[] }
  | { type: "missing" }
>;

export async function parseDotLightfast(
  fetch: Fetcher
): Promise<Result<DotLightfastConfig, ConfigError>>
```

This decouples parsing from I/O. The Inngest function provides a `Fetcher` that wraps `platform.proxy.execute({ endpointId: "get-file-contents" })`.

**Why not reuse `loadConfig`:** `loadConfig` is tightly bound to `readFile` + a single `lightfast.yml` at the root. The `.lightfast/` config is a directory tree fetched via HTTP. Different I/O, different shape.

**Export from `@repo/app-config`:**
```ts
export { parseDotLightfast, SkillFrontmatterSchema,
         type DotLightfastConfig, type SkillManifest } from "./dotlightfast";
```

